            jarMarkerAdded = true;
        }
        super.putArchiveEntry(zipEntry);
    }

    private ZipArchiveEntry copyEntryWithJarMarker(ZipArchiveEntry original) {
        ZipArchiveEntry copy = new ZipArchiveEntry(original.getName());
        // Copy all properties from original to copy
        copy.setTime(original.getTime());
        copy.setSize(original.getSize());
        copy.setCompressedSize(original.getCompressedSize());
        copy.setCrc(original.getCrc());
        copy.setMethod(original.getMethod());
        copy.setComment(original.getComment());
        copy.setInternalAttributes(original.getInternalAttributes());
        copy.setExternalAttributes(original.getExternalAttributes());
